}

import { useEffect, useState } from "react";

export default function OrderSummary({ orderId }) {
  const [order, setOrder] = useState();

  useEffect(() => {
    fetch(`/api/orders/${orderId}`)
      .then(res => res.json())
      .then(data => setOrder(data));
  }, [orderId]);

  if (!order) return <p>Loading…</p>;

  return (
    <div>
      <h2>Order #{order.order_id}</h2>
      <p>Customer: {order.customer_email}</p>
      <p>Placed: {order.placed_at}</p>
    </div>
  );
}

function snakeToCamel(value) {
  if (Array.isArray(value)) return value.map(snakeToCamel);
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value).map(([k, v]) => [
        k.replace(/_([a-z])/g, (_, c) => c.toUpperCase()),
        snakeToCamel(v),
      ])
    );
  }
  return value;
}

export default function OrderSummary({ orderId }) {
  const [order, setOrder] = useState();

  useEffect(() => {
    fetch(`/api/orders/${orderId}`)
      .then(res => res.json())
      .then(raw => setOrder(snakeToCamel(raw)));
  }, [orderId]);

  if (!order) return <p>Loading…</p>;
  return <div>... order.orderId, order.customerEmail, order.placedAt ...</div>;
}
